+            </dialog>
+        );
+    }
+
+    return (
+        <div
+            ref={ref as Ref<HTMLDivElement>}
+            role={role || 'dialog'}
+            hidden={!open}
+            data-dialog-open={open ? '' : undefined}
+            {...rest}
+        >
+            {children}
+        </div>
+    );
+});
+
 Dialog.displayName = 'Dialog';

 export default Dialog;
